                                    <span className="text-muted-foreground">
                                      —
                                    </span>
                                  )}
                                </TableCell>
                                <TableCell>
                                  {row.teamName ? (
                                    <span className="font-medium">
                                      {row.teamName}
                                    </span>
                                  ) : (
                                    <span className="text-muted-foreground">
                                      —
                                    </span>
                                  )}
                                </TableCell>
                                <TableCell>
                                  {row.athlete.affiliateName ? (
                                    <span>{row.athlete.affiliateName}</span>
                                  ) : (
                                    <span className="text-muted-foreground">
                                      —
                                    </span>
