/**
 * Competition Organizer Layout Route
 *
 * Layout route for organizer competition detail pages with sidebar navigation.
 * Fetches competition data, verifies user permissions, and provides context to child routes.
 */
// @lat: [[organizer-dashboard#Layout and Access Control]]

import {
  createFileRoute,
  notFound,
  Outlet,
  redirect,
  useMatches,
} from "@tanstack/react-router"
import { CompetitionHeader } from "@/components/competition-header"
import { CompetitionSidebar } from "@/components/competition-sidebar"
import { OrganizerBreadcrumb } from "@/components/organizer-breadcrumb"
import { PendingOrganizerBanner } from "@/components/pending-organizer-banner"
import { getCompetitionByIdFn } from "@/server-fns/competition-detail-fns"

export const Route = createFileRoute("/compete/organizer/$competitionId")({
  component: CompetitionLayout,
  staleTime: 10_000, // Cache for 10 seconds (SWR behavior)
  loader: async ({ params, context }) => {
    const session = context.session

    // Require authentication
    if (!session?.user?.id) {
      throw redirect({
        to: "/sign-in",
        search: { redirect: `/compete/organizer/${params.competitionId}` },
      })
    }

    // Get competition by ID
    const { competition } = await getCompetitionByIdFn({
      data: { competitionId: params.competitionId },
    })

    if (!competition) {
      throw notFound()
    }

    // Verify user can manage this competition using session data
    const canManage =
      session.user?.role === "admin" ||
      !!session.teams?.find(
        (t) =>
          t.id === competition.organizingTeamId &&
          (t.role.id === "admin" || t.role.id === "owner"),
      )

    if (!canManage) {
      throw redirect({
        to: "/compete",
        search: {},
      })
    }

    return {
      competition,
    }
  },
})

// Map route paths to breadcrumb labels
// Note: "results" label is handled dynamically based on competition type
const routeLabels: Record<string, string> = {
  divisions: "Divisions",
  athletes: "Registrations",
  events: "Events",
  "event-divisions": "Event Divisions",
  "submission-windows": "Submission Windows",
  schedule: "Schedule",
  locations: "Locations",
  volunteers: "Volunteers",
  results: "Results", // Overridden to "Submissions" for online competitions
  review: "Review",
  pricing: "Pricing",
  revenue: "Revenue",
  coupons: "Coupons",
  sponsors: "Sponsors",
  settings: "Settings",
  edit: "Edit",
  "danger-zone": "Danger Zone",
}

function CompetitionLayout() {
  const { competition } = Route.useLoaderData()
  const { entitlements } = Route.useRouteContext()
  const matches = useMatches()

  // Get the current child route segment for breadcrumb
  const currentPath = matches[matches.length - 1]?.pathname ?? ""
  const segments = currentPath.split("/").filter(Boolean)
  const lastSegment = segments[segments.length - 1]

  // Build breadcrumb segments
  const breadcrumbSegments: Array<{ label: string; href?: string }> = [
    { label: competition.name },
  ]

  // Add current page to breadcrumb if not on overview
  if (lastSegment && lastSegment !== competition.id) {
    let label = routeLabels[lastSegment] || lastSegment
    // Show "Submissions" instead of "Results" for online competitions
    if (lastSegment === "results" && competition.competitionType === "online") {
      label = "Submissions"
    }
    breadcrumbSegments.push({ label })
  }

  return (
    <CompetitionSidebar
      competitionId={competition.id}
      competitionType={competition.competitionType}
    >
      {entitlements.isPendingApproval && (
        <PendingOrganizerBanner variant="sidebar-inset" />
      )}
      <div className="flex flex-1 flex-col gap-4 p-4 sm:gap-6 sm:p-6">
        {/* Breadcrumb */}
        <OrganizerBreadcrumb segments={breadcrumbSegments} />

        {/* Competition Header */}
        <CompetitionHeader
          competition={{
            id: competition.id,
            name: competition.name,
            slug: competition.slug,
            description: competition.description,
            startDate: competition.startDate,
            endDate: competition.endDate,
            registrationOpensAt: competition.registrationOpensAt,
            registrationClosesAt: competition.registrationClosesAt,
            visibility: competition.visibility,
            status: competition.status,
            groupId: competition.groupId,
          }}
        />

        {/* Child route content */}
        <Outlet />
      </div>
    </CompetitionSidebar>
  )
}

export const getRegistrationDetailsFn = createServerFn({ method: "GET" })
  .inputValidator((data: unknown) =>
    z.object({ registrationId: z.string() }).parse(data),
  )
  .handler(async ({ data }): Promise<RegistrationDetails | null> => {
    const session = await requireVerifiedEmail()
    if (!session) throw new Error("Unauthorized")

    const db = getDb()
    const { competitionDivisionsTable } = await import("@/db/schema")

    // Get registration with all related data
    const registration = await db.query.competitionRegistrationsTable.findFirst(
      {
        where: eq(competitionRegistrationsTable.id, data.registrationId),
        with: {
          competition: {
            columns: {
              id: true,
              name: true,
              slug: true,
              startDate: true,
              endDate: true,
              profileImageUrl: true,
            },
          },
          division: {
            columns: {
              id: true,
              label: true,
              teamSize: true,
            },
          },
        },
      },
    )

    if (!registration) {
      return null
    }

    // Verify user is authorized to view this registration
    const isRegisteredUser = registration.userId === session.user.id
    let isTeamMember = false
    if (registration.athleteTeamId) {
      const membership = await db.query.teamMembershipTable.findFirst({
        where: and(
          eq(teamMembershipTable.teamId, registration.athleteTeamId),
          eq(teamMembershipTable.userId, session.user.id),
        ),
      })
      isTeamMember = !!membership
    }
    if (!isRegisteredUser && !isTeamMember) {
      // Return null instead of throwing to allow route to show 404
      return null
    }

    // Parse related data (handle array vs single object)
    const competition = registration.competition
      ? Array.isArray(registration.competition)
        ? registration.competition[0]
        : registration.competition
      : null

    const division = registration.division
      ? Array.isArray(registration.division)
        ? registration.division[0]
        : registration.division
      : null

    // Get division description and fee from competition_divisions table
    let divisionDescription: string | null = null
    let divisionFeeCents: number | null = null

    if (competition?.id && division?.id) {
      const divisionConfig = await db.query.competitionDivisionsTable.findFirst(
        {
          where: and(
            eq(competitionDivisionsTable.competitionId, competition.id),
            eq(competitionDivisionsTable.divisionId, division.id),
          ),
        },
      )
      if (divisionConfig) {
        divisionDescription = divisionConfig.description
        divisionFeeCents = divisionConfig.feeCents
      }
    }

    // Get purchase details if exists
    let purchase: RegistrationDetails["purchase"] = null
    let isOriginalPurchaser = false
    let purchaserName: string | null = null

    if (registration.commercePurchaseId) {
      const purchaseRecord = await db.query.commercePurchaseTable.findFirst({
        where: eq(commercePurchaseTable.id, registration.commercePurchaseId),
      })
      if (purchaseRecord) {
        let couponCode: string | null = null
        let couponDiscountCents: number | null = null
        if (purchaseRecord.metadata) {
          try {
            const meta = JSON.parse(purchaseRecord.metadata)
            couponCode = meta.couponCode ?? null
            couponDiscountCents = meta.couponDiscountCents ?? null
          } catch {
            // ignore invalid metadata
          }
        }
        purchase = {
          id: purchaseRecord.id,
          totalCents: purchaseRecord.totalCents,
          status: purchaseRecord.status,
          completedAt: purchaseRecord.completedAt,
          stripePaymentIntentId: purchaseRecord.stripePaymentIntentId,
          couponCode,
          couponDiscountCents,
        }
        isOriginalPurchaser = purchaseRecord.userId === session.user.id
        if (!isOriginalPurchaser) {
          const payer = await db.query.userTable.findFirst({
            where: eq(userTable.id, purchaseRecord.userId),
            columns: { firstName: true, lastName: true },
          })
          if (payer) {
            purchaserName =
              [payer.firstName, payer.lastName].filter(Boolean).join(" ") ||
              null
          }
        }
      }
    }

    return {
      registrationId: registration.id,
      registeredAt: registration.registeredAt,
      status: registration.status,
      teamName: registration.teamName,
      paymentStatus: registration.paymentStatus,
      paidAt: registration.paidAt,
      competition: competition
        ? {
            id: competition.id,
            name: competition.name,
            slug: competition.slug,
            startDate: competition.startDate,
            endDate: competition.endDate,
            profileImageUrl: competition.profileImageUrl,
          }
        : null,
      division: division
        ? {
            id: division.id,
            label: division.label,
            teamSize: division.teamSize,
            description: divisionDescription,
            feeCents: divisionFeeCents,
          }
        : null,
      purchase,
      isOriginalPurchaser,
      purchaserName,
    }
  })

/**
 * Cancel any pending purchases for a user/competition
 * Used when user explicitly cancels from Stripe checkout
 * This releases the reservation immediately instead of waiting for timeout
 */
export const cancelPendingPurchaseFn = createServerFn({ method: "POST" })
  .inputValidator((data: unknown) =>
    z
      .object({
        userId: z.string().min(1, "User ID is required"),
        competitionId: z.string().min(1, "Competition ID is required"),
      })
      .parse(data),
  )
  .handler(async ({ data }) => {
    // Authenticate user
    const session = await requireVerifiedEmail()
    if (!session) throw new Error("Unauthorized")

    // Update request context
    updateRequestContext({ userId: session.user.id })
    addRequestContextAttribute("competitionId", data.competitionId)
    getEvlog()?.set({ action: "cancel_registration", registration: { competitionId: data.competitionId } })

    // Ensure user can only cancel their own pending purchases
    if (data.userId !== session.user.id) {
      logWarning({
        message: "[Registration] Cancel purchase denied - wrong user",
        attributes: {
          requestedUserId: data.userId,
          competitionId: data.competitionId,
        },
      })

/**
 * Competition Event Layout Route
 *
 * Layout route for a single competition event. Loads event details,
 * divisions, movements, sponsors, and judging sheets for child routes.
 */

import { Outlet, createFileRoute } from "@tanstack/react-router"
import { getCompetitionDivisionsWithCountsFn } from "@/server-fns/competition-divisions-fns"
import { getCompetitionEventsFn } from "@/server-fns/competition-event-fns"
import {
  getCompetitionEventFn,
  getCompetitionWorkoutsFn,
  getWorkoutDivisionDescriptionsFn,
} from "@/server-fns/competition-workouts-fns"
import { getEventDivisionMappingsFn } from "@/server-fns/event-division-mapping-fns"
import { getEventResourcesFn } from "@/server-fns/event-resources-fns"
import { getEventJudgingSheetsFn } from "@/server-fns/judging-sheet-fns"
import { getAllMovementsFn } from "@/server-fns/movement-fns"
import { getCompetitionSponsorsFn } from "@/server-fns/sponsor-fns"

export const Route = createFileRoute(
  "/compete/organizer/$competitionId/events/$eventId",
)({
  staleTime: 10_000,
  component: () => <Outlet />,
  loader: async ({ params, parentMatchPromise }) => {
    const parentMatch = await parentMatchPromise
    const { competition } = parentMatch.loaderData!

    const isOnline = competition.competitionType === "online"

    // Parallel fetch event, divisions, movements, sponsors, resources, judging sheets, competition events, and mappings
    const [
      eventResult,
      divisionsResult,
      movementsResult,
      sponsorsResult,
      resourcesResult,
      judgingSheetsResult,
      competitionEventsResult,
      mappingsResult,
    ] = await Promise.all([
      getCompetitionEventFn({
        data: {
          trackWorkoutId: params.eventId,
          teamId: competition.organizingTeamId,
        },
      }),
      getCompetitionDivisionsWithCountsFn({
